import { useCallback, useMemo, useState, useEffect } from "react"
import dayjs from "dayjs"
import {
  MainTableHeader,
  SubTableHeader,
} from "src/components/Table/CustomTable/styled"
import { Row, Col, Input, InputNumber, DatePicker } from "antd"
import SpinCustom from "src/components/SpinCustom"
import ModalManageAdvertisementRegistraion from "./modal/ModalManageAdvertisementRegistraion"
import TableCustom from "src/components/Table/CustomTable"
import TitleCustom from "src/components/TitleCustom"
import AdvertisementApi from "src/services/ManageAdvertisementRegistraion"

const columns = [
  {
    title: (
      <>
        <MainTableHeader>Mã hợp đồng</MainTableHeader>
      </>
    ),
    dataIndex: "ContractCode",
    key: "ContractCode",
    render: value => value || "N/A",
  },
  {
    title: (
      <>
        <MainTableHeader>Ngày tạo Đơn</MainTableHeader>
      </>
    ),
    dataIndex: "CreatedAt",
    key: "CreatedAt",
    render: value => (value ? dayjs(value).format("DD/MM/YYYY HH:mm") : "N/A"),
  },
  {
    title: (
      <>
        <MainTableHeader>Thời hạn</MainTableHeader>
        <SubTableHeader>(Bắt đầu - Kết thúc)</SubTableHeader>
      </>
    ),
    key: "date-range",
    render: (_, record) => {
      const startDate = record.StartDate
        ? dayjs(record.StartDate).format("DD/MM/YYYY")
        : "N/A"
      const endDate = record.EndDate
        ? dayjs(record.EndDate).format("DD/MM/YYYY")
        : "N/A"
      return (
        <div>
          Từ: {startDate} <br />
          Đến: {endDate}
        </div>
      )
    },
  },
  {
    title: (
      <>
        <MainTableHeader>Vị trí đặt trong trang</MainTableHeader>
      </>
    ),
    key: "PositionNames",
    render: (_, record) => (
      <div>
        {record?.PositionNames?.map((p, idx) => (
          <span key={idx}>
            {p}
            {idx < record.PositionNames.length - 1 ? ", " : ""}
          </span>
        )) || "N/A"}
      </div>
    ),
  },
  {
    title: "Giá trị",
    dataIndex: "Amount",
    key: "Amount",
    render: value => (value ? `${value.toLocaleString()} VND` : "N/A"),
  },
  {
    title: "Người đại diện",
    dataIndex: "RepresentativeName",
    key: "RepresentativeName",
    render: value => value || "N/A",
  },
  {
    title: "Trạng thái",
    dataIndex: "Status",
    key: "Status",
    render: status => {
      let text = "N/A"
      let style = {}
      switch (status) {
        case 0:
          text = "Tạm"
          style = { color: "#999" }
          break
        case 1:
          text = "Đã thanh toán (Chờ xem xét)"
          style = { color: "#1890ff", fontWeight: "bold" }
          break
        case 2:
          text = "Đồng ý"
          style = { color: "green", fontWeight: "bold" }
          break
        case 3:
          text = "Từ chối"
          style = { color: "red", fontWeight: "bold" }
          break
        case 4:
          text = "Hết hạn"
          style = { color: "orange", fontWeight: "bold" }
          break
        default:
          break
      }
      return <div style={style}>{text}</div>
    },
  },
]

const index = () => {
  const { RangePicker } = DatePicker
  const [loading, setLoading] = useState(false)
  const [list, setList] = useState({
    data: [],
    total: 0,
  })

  const [isDetailModalVisible, setIsDetailModalVisible] = useState(false)
  const [selectedRecordDetail, setSelectedRecordDetail] = useState(null)

  const [pagination, setPagination] = useState({
    CurrentPage: 1,
    PageSize: 10,
  })

  const [filters, setFilters] = useState({
    searchText: "",
    fromDate: null,
    toDate: null,
  })

  const resetToFirstPage = () =>
    setPagination(prev => ({ ...prev, CurrentPage: 1 }))

  useEffect(() => {
    loadData()
  }, [pagination.CurrentPage, pagination.PageSize])

  const loadData = useCallback(async () => {
    setLoading(true)
    try {
      const res = await AdvertisementApi.GetAdvertisingContractsOfCurrentUser()
      console.log("<<<<<<<<<< LOAD DATA >>>>>>>>>>>>>>")
      console.log("Res object >>>>>>: ", res?.Object)
      if (res?.isOk) {
        setList({ data: res.Object, total: res.Object.length })
      }
    } catch (e) {
      setList({ data: [], total: 0 })
    } finally {
      setLoading(false)
    }
  }, [
    pagination.CurrentPage,
    pagination.PageSize,
    filters.searchText,
    filters.fromDate,
    filters.toDate,
  ])

  const handleRowClick = record => {
    setSelectedRecordDetail(record)
    setIsDetailModalVisible(true)
  }

  const handleCloseDetailModal = () => {
    setIsDetailModalVisible(false)
    setSelectedRecordDetail(null)
  }

  const filteredData = useMemo(() => {
    const q = (filters.searchText || "").trim().toLowerCase()
    const from = filters.fromDate
    const to = filters.toDate

    return (list.data || []).filter(item => {
      const bySearch =
        !q ||
        (item?.ContractCode || "").toLowerCase().includes(q) ||
        (item?.RepresentativeName || "").toLowerCase().includes(q)

      const start = item?.StartDate ? dayjs(item.StartDate) : null
      const end = item?.EndDate ? dayjs(item.EndDate) : null

      const byDate =
        (!from && !to) ||
        (start &&
          end &&
          (!from || start.isSame(from, "day") || start.isAfter(from, "day")) &&
          (!to || end.isSame(to, "day") || end.isBefore(to, "day")))

      return bySearch && byDate
    })
  }, [list.data, filters.searchText, filters.fromDate, filters.toDate])

  return (
    <SpinCustom spinning={loading}>
      <TitleCustom className="d-flex-sb">
        <span>Danh sách đơn đăng ký quảng cáo</span>
      </TitleCustom>
      <Row gutter={12} style={{ marginBottom: 12 }}>
        <Col span={8}>
          <Input.Search
            allowClear
            placeholder="Tìm theo mã hợp đồng hoặc tên người đại diện"
            value={filters.searchText}
            onChange={e =>
              setFilters(prev => ({ ...prev, searchText: e.target.value }))
            }
          />
        </Col>
        <Col span={8}>
          <RangePicker
            style={{ width: "100%" }}
            format="DD/MM/YYYY"
            value={
              filters.fromDate && filters.toDate
                ? [filters.fromDate, filters.toDate]
                : []
            }
            onChange={dates =>
              setFilters(prev => ({
                ...prev,
                fromDate: dates ? dates[0] : null,
                toDate: dates ? dates[1] : null,
              }))
            }
            placeholder={["Từ ngày bắt đầu", "Đến ngày kết thúc"]}
          />
        </Col>
      </Row>

      <TableCustom
        dataSource={filteredData}
        columns={columns}
        rowKey="ID"
        onRow={record => {
          return {
            onClick: event => {
              const selection = window.getSelection()
              const isTextSelected =
                selection && selection.toString().length > 0
              if (
                !isTextSelected &&
                !event.target.closest(".float-action__wrapper")
              ) {
                handleRowClick(record)
              }
            },
          }
        }}
        pagination={{
          current: pagination.CurrentPage,
          pageSize: pagination.PageSize,
          total: filteredData.length,
          onChange: (page, pageSize) => {
            setPagination({ CurrentPage: page, PageSize: pageSize })
          },
          onShowSizeChange: (page, pageSize) => {
            setPagination({ CurrentPage: page, PageSize: pageSize })
          },
          showSizeChanger: true,
        }}
      />
      {isDetailModalVisible && (
        <ModalManageAdvertisementRegistraion
          onCancel={handleCloseDetailModal}
          selectedRecord={selectedRecordDetail}
          open={isDetailModalVisible}
        />
      )}
    </SpinCustom>
  )
}

export default index
