import { Descriptions, Modal, Typography } from "antd"
const { Text } = Typography
import dayjs from "dayjs"

const ModalManageAdvertisementRegistraion = ({
  open,
  onCancel,
  selectedRecord,
}) => {
  return (
    <Modal
      title={"Chi tiết đơn đăng ký quảng cáo"}
      open={open}
      width={700}
      onCancel={onCancel}
    >
      <>
        <Descriptions bordered column={1} size="middle">
          <Descriptions.Item label="ID hợp đồng">
            <Text>{selectedRecord?.AdContractId || "N/A"}</Text>
          </Descriptions.Item>
          <Descriptions.Item label="Mã Hợp đồng">
            <Text>{selectedRecord?.ContractCode || "N/A"}</Text>
          </Descriptions.Item>
          <Descriptions.Item label="Tên người đại diện">
            <Text>{selectedRecord?.RepresentativeName || "N/A"}</Text>
          </Descriptions.Item>
          <Descriptions.Item label="Loại thành viên">
            <Text>
              {selectedRecord?.MemberType === 1
                ? "Cá nhân"
                : selectedRecord?.MemberType === 2
                ? "Doanh nghiệp"
                : "N/A"}
            </Text>
          </Descriptions.Item>
          <Descriptions.Item label="Số điện thoại">
            <Text>{selectedRecord?.PhoneNumber || "N/A"}</Text>
          </Descriptions.Item>
          <Descriptions.Item label="Email">
            <Text>{selectedRecord?.Email || "N/A"}</Text>
          </Descriptions.Item>
          <Descriptions.Item label="Ngày tạo đơn">
            <Text>
              {selectedRecord?.CreatedAt
                ? dayjs(selectedRecord.CreatedAt).format("DD/MM/YYYY HH:mm")
                : "N/A"}
            </Text>
          </Descriptions.Item>
          <Descriptions.Item label="Thời hạn">
            <Text>
              {selectedRecord?.StartDate && selectedRecord?.EndDate
                ? `${dayjs(selectedRecord.StartDate).format(
                    "DD/MM/YYYY",
                  )} - ${dayjs(selectedRecord.EndDate).format("DD/MM/YYYY")}`
                : "N/A"}
            </Text>
          </Descriptions.Item>
          <Descriptions.Item label="Giá trị hợp đồng">
            <Text>
              {selectedRecord?.Amount
                ? `${selectedRecord.Amount.toLocaleString()} VND`
                : "N/A"}
            </Text>
          </Descriptions.Item>
          <Descriptions.Item label="Phương thức thanh toán">
            <Text>
              {selectedRecord?.PaymentMethod === 1
                ? "Online"
                : selectedRecord?.PaymentMethod === 2
                ? "Offline"
                : "N/A"}
            </Text>
          </Descriptions.Item>
          <Descriptions.Item label="Trạng thái">
            <Text>
              {(() => {
                switch (selectedRecord?.Status) {
                  case 0:
                    return "Tạm"
                  case 1:
                    return "Đã thanh toán (Chờ xem xét)"
                  case 2:
                    return "Đồng ý"
                  case 3:
                    return "Từ chối"
                  case 4:
                    return "Hết hạn"
                  default:
                    return "N/A"
                }
              })()}
            </Text>
          </Descriptions.Item>
          <Descriptions.Item label="Người giới thiệu">
            <Text>
              {selectedRecord?.Referrer?.FullName ||
                selectedRecord?.Referrer?.PhoneNumber ||
                "N/A"}
            </Text>
          </Descriptions.Item>
        </Descriptions>
      </>
    </Modal>
  )
}

export default ModalManageAdvertisementRegistraion
